def solve_knight_tour(n):
    dx = [-2, -2, -1, -1, 1, 1, 2, 2]
    dy = [-1, 1, -2, 2, -2, 2, -1, 1]

    board = [[-1 for _ in range(n)] for _ in range(n)]

    def is_valid(x, y):
        return 0 <= x < n and 0 <= y < n and board[x][y] == -1

    def print_board():
        for row in board:
            for cell in row:
                print(f"{cell:3}", end="")
            print()

    def solve(curr_x, curr_y, move_count):
        if move_count == n * n:
            print_board()
            return True

        for i in range(8):
            next_x, next_y = curr_x + dx[i], curr_y + dy[i]

            if is_valid(next_x, next_y):
                board[next_x][next_y] = move_count + 1
                if solve(next_x, next_y, move_count + 1):
                    return True
                board[next_x][next_y] = -1
        return False

    board[0][0] = 1
    if not solve(0, 0, 1):
        pass

solve_knight_tour(5)
